// Extract key fields from the WhatsApp webhook payload
const entry = items[0].json.entry[0];
const change = entry.changes[0];
const value = change.value;
const message = value.messages[0];
const contact = value.contacts?.[0];

const from = message.from;          // Sender's WhatsApp number
const msgId = message.id;            // Unique message ID (use to prevent double-replies)
const msgText = message.text.body;   // The actual message text
const timestamp = message.timestamp; // Unix timestamp
const senderName = contact?.profile?.name || 'Guest';

return [{
  json: {
    from,
    msgId,
    msgText,
    timestamp,
    senderName,
    phoneNumberId: value.metadata.phone_number_id,
  }
}];

// Build the messages array for the Claude / OpenAI API call
const currentMessage = items[0].json.msgText;
const senderName = items[0].json.senderName;
let history = [];

// Parse stored history (Redis returns a JSON string)
try {
  const raw = items[0].json.value || '[]';
  history = JSON.parse(raw);
} catch(e) {
  history = [];
}

// Append the new message
history.push({ role: 'user', content: currentMessage });

// Keep only last 20 messages (10 exchanges) to control token cost
if (history.length > 20) history = history.slice(-20);

return [{
  json: {
    ...items[0].json,
    messages: history,
    senderName,
  }
}];

