// Extract Maria's reply from the Claude API response
const response = items[0].json;
const reply = response.content[0].text;
const from = items[0].json.from;
const phoneNumberId = items[0].json.phoneNumberId;
let messages = items[0].json.messages;

// Add Maria's reply to the history
messages.push({ role: 'assistant', content: reply });

return [{
  json: {
    from,
    phoneNumberId,
    reply,
    messages,
    senderName: items[0].json.senderName,
    timestamp: items[0].json.timestamp,
  }
}];

// Log inquiry to Firebase Firestore (or your database of choice)
// This node calls your Firebase REST API to store the lead

const data = {
  from: items[0].json.from,
  senderName: items[0].json.senderName,
  lastMessage: items[0].json.reply,
  timestamp: new Date().toISOString(),
  source: 'whatsapp',
  status: 'active',
};

// Check if the message history suggests an enquiry was captured
const messages = items[0].json.messages || [];
const allText = messages.map(m => m.content).join(' ').toLowerCase();
const likelyEnquiry = allText.includes('proposal') || allText.includes('dates') || allText.includes('guests') || allText.includes('charter');

data.enquiryLikely = likelyEnquiry;

return [{ json: data }];
